import{_ as o,c as d,o as e,ag as r}from"./chunks/framework.bCALENAD.js";const a="/assets/BrowserCachingStrategy.DkiIZ2mY.png",u=JSON.parse('{"title":"网络","description":"","frontmatter":{},"headers":[],"relativePath":"notes/others/network.md","filePath":"notes/others/network.md","lastUpdated":1772248165000}'),s={name:"notes/others/network.md"};function n(i,t,l,c,h,g){return e(),d("div",null,[...t[0]||(t[0]=[r(`<h1 id="网络" tabindex="-1">网络 <a class="header-anchor" href="#网络" aria-label="Permalink to &quot;网络&quot;">​</a></h1><h2 id="基础概念" tabindex="-1">基础概念 <a class="header-anchor" href="#基础概念" aria-label="Permalink to &quot;基础概念&quot;">​</a></h2><h3 id="浏览器从输入url到显示页面的过程" tabindex="-1">浏览器从输入URL到显示页面的过程 <a class="header-anchor" href="#浏览器从输入url到显示页面的过程" aria-label="Permalink to &quot;浏览器从输入URL到显示页面的过程&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">流程</p><blockquote><ol><li>用户输入 URL 并回车</li><li>DNS 解析</li><li>建立 TCP 连接，发起 HTTP 请求</li><li>服务器处理并返回响应</li><li>浏览器接收响应并开始解析</li><li>布局（Layout / Reflow）</li><li>绘制</li><li>合成（Composite）</li><li>后续资源加载与交互</li></ol></blockquote></div><h4 id="第-1-步-用户输入-url-并回车" tabindex="-1">第 1 步：用户输入 URL 并回车 <a class="header-anchor" href="#第-1-步-用户输入-url-并回车" aria-label="Permalink to &quot;第 1 步：用户输入 URL 并回车&quot;">​</a></h4><ul><li>浏览器解析输入内容： <ul><li>如果是关键词（如 “天气”），可能走默认搜索引擎；</li><li>如果是合法 URL（如 <code>https://github.com/</code>），进入下一步。</li></ul></li></ul><h4 id="第-2-步-dns-解析-将域名转为-ip-地址" tabindex="-1">第 2 步：DNS 解析（将域名转为 IP 地址） <a class="header-anchor" href="#第-2-步-dns-解析-将域名转为-ip-地址" aria-label="Permalink to &quot;第 2 步：DNS 解析（将域名转为 IP 地址）&quot;">​</a></h4><p><strong>浏览器检查缓存顺序：</strong></p><p>DNS缓存 -&gt; 本地Hosts文件 -&gt; 向本地DNS服务器发起查询 -&gt; 若未命中，递归查询根域名服务器/顶级域（.com）/权威DNS服务器</p><ul><li>最终获得目标服务器的 <strong>IP 地址</strong>（如 <code>20.205.243.166</code>）</li></ul><h4 id="第-3-步-建立-tcp-连接-发起-http-请求" tabindex="-1">第 3 步：建立 TCP 连接，发起 HTTP 请求 <a class="header-anchor" href="#第-3-步-建立-tcp-连接-发起-http-请求" aria-label="Permalink to &quot;第 3 步：建立 TCP 连接，发起 HTTP 请求&quot;">​</a></h4><ul><li>浏览器通过 <strong>TCP 协议</strong> 与服务器 IP 建立连接（默认端口 80/HTTP 或 443/HTTPS）。</li><li>浏览器构造 HTTP 请求报文</li><li>通过已建立的 TCP（或 QUIC）连接发送请求。</li></ul><h4 id="第-4-步-服务器处理并返回响应" tabindex="-1">第 4 步：服务器处理并返回响应 <a class="header-anchor" href="#第-4-步-服务器处理并返回响应" aria-label="Permalink to &quot;第 4 步：服务器处理并返回响应&quot;">​</a></h4><ul><li>服务器收到请求后： <ul><li>路由匹配</li><li>执行后端逻辑（如查询数据库）</li><li>生成 HTML 内容</li></ul></li><li>返回 HTTP 响应</li></ul><h4 id="第-5-步-浏览器接收响应并开始解析" tabindex="-1">第 5 步：浏览器接收响应并开始解析 <a class="header-anchor" href="#第-5-步-浏览器接收响应并开始解析" aria-label="Permalink to &quot;第 5 步：浏览器接收响应并开始解析&quot;">​</a></h4><ol><li><p>解析 HTML 构建 DOM 树</p><ul><li>浏览器逐字节解析 HTML，遇到标签就创建 DOM 节点。</li><li><strong>遇到 <code>&lt;script&gt;</code></strong>： <ul><li>若无 <code>async</code>/<code>defer</code>：<strong>阻塞 HTML 解析</strong>，立即下载并执行 JS。</li><li><code>defer</code>：延迟到 DOM 解析完后执行（按顺序）。</li><li><code>async</code>：异步下载，下载完立即执行（不保证顺序）。</li></ul></li><li><strong>遇到 <code>&lt;link rel=&quot;stylesheet&quot;&gt;</code></strong>： <ul><li>CSS 不阻塞 HTML 解析，但<strong>阻塞 DOM 渲染</strong>（因需构建 CSSOM）。</li></ul></li></ul></li><li><p>加载 CSS 并构建 CSSOM</p><ul><li>下载 CSS 文件 → 解析 → 构建 <strong>CSSOM（CSS Object Model）</strong></li><li>CSSOM 与 DOM 结合形成 <strong>Render Tree（渲染树）</strong></li></ul></li><li><p>构建 Render Tree</p><ul><li>Render Tree = DOM + CSSOM（只包含可见元素，如 <code>display: none</code> 的节点会被剔除）</li></ul></li></ol><h4 id="第-6-步-布局-layout-reflow" tabindex="-1">第 6 步：布局（Layout / Reflow） <a class="header-anchor" href="#第-6-步-布局-layout-reflow" aria-label="Permalink to &quot;第 6 步：布局（Layout / Reflow）&quot;">​</a></h4><ul><li>计算每个 Render Tree 节点的<strong>几何信息</strong>（位置、大小）。这个过程也叫 <strong>Reflow</strong>。根节点（viewport）开始，递归计算。</li></ul><h4 id="第-7-步-绘制-paint-rasterization" tabindex="-1">第 7 步：绘制（Paint / Rasterization） <a class="header-anchor" href="#第-7-步-绘制-paint-rasterization" aria-label="Permalink to &quot;第 7 步：绘制（Paint / Rasterization）&quot;">​</a></h4><ul><li>将 Render Tree 转换为屏幕上的像素。</li><li>分层（Layer）处理：如 transform、opacity 元素会提升为单独图层。</li><li>绘制指令发送给 GPU（合成阶段）。</li></ul><h4 id="第-8-步-合成-composite" tabindex="-1">第 8 步：合成（Composite） <a class="header-anchor" href="#第-8-步-合成-composite" aria-label="Permalink to &quot;第 8 步：合成（Composite）&quot;">​</a></h4><ul><li>浏览器将多个图层<strong>按顺序合并</strong>，生成最终图像。</li><li>由 <strong>Compositor 线程</strong>完成，不阻塞主线程。</li><li>显示在屏幕上。</li></ul><blockquote><p>✅ 至此，<strong>首屏内容已渲染完成（First Paint / First Contentful Paint）</strong></p></blockquote><h4 id="第-9-步-后续资源加载与交互" tabindex="-1">第 9 步：后续资源加载与交互 <a class="header-anchor" href="#第-9-步-后续资源加载与交互" aria-label="Permalink to &quot;第 9 步：后续资源加载与交互&quot;">​</a></h4><ul><li>执行 JS（如 <code>DOMContentLoaded</code> 事件触发）</li><li>加载图片、视频、字体等非关键资源</li><li>执行 <code>window.onload</code>（所有资源加载完毕）</li><li>用户可交互（如点击按钮、滚动）</li></ul><h3 id="网络层级-osi-七层模型" tabindex="-1">网络层级 - OSI 七层模型 <a class="header-anchor" href="#网络层级-osi-七层模型" aria-label="Permalink to &quot;网络层级 - OSI 七层模型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>层数</th><th>名称</th><th>核心功能</th><th>前端是否关心？</th><th>关联前端场景</th></tr></thead><tbody><tr><td>7</td><td>应用层（Application）</td><td>提供用户接口和网络服务（如 HTTP、FTP、SMTP）</td><td>✅ 高度相关</td><td><code>fetch()</code>、<code>XMLHttpRequest</code>、WebSocket、API 调用、浏览器地址栏访问网页</td></tr><tr><td>6</td><td>表示层（Presentation）</td><td>数据格式转换、加密解密、压缩</td><td>⚠️ 间接相关</td><td>HTTPS 中的 TLS 加密（如证书、AES）、JSON/XML 编码、图片压缩（WebP）</td></tr><tr><td>5</td><td>会话层（Session）</td><td>建立、管理和终止会话（对话控制）</td><td>⚠️ 基本不直接接触</td><td>登录会话（Session ID）、WebSocket 长连接维持（可视为会话）</td></tr><tr><td>4</td><td>传输层（Transport）</td><td>端到端通信、可靠传输（TCP）或快速传输（UDP）</td><td>⚠️ 需了解概念</td><td>TCP 保证请求完整到达；HTTP/HTTPS 基于 TCP；WebSocket 也基于 TCP</td></tr><tr><td>3</td><td>网络层（Network）</td><td>路由选择、IP 寻址</td><td>❌ 不关心</td><td>IP 地址分配、路由器转发（由操作系统/网络设备处理）</td></tr><tr><td>2</td><td>数据链路层（Data Link）</td><td>同一局域网内设备通信（MAC 地址）</td><td>❌ 不关心</td><td>Wi-Fi、以太网帧传输（底层硬件处理）</td></tr><tr><td>1</td><td>物理层（Physical）</td><td>传输比特流（电压、光信号等）</td><td>❌ 完全无关</td><td>网线、光纤、无线信号</td></tr></tbody></table><table tabindex="0"><thead><tr><th>应用层协议</th><th>作用</th><th>前端场景</th></tr></thead><tbody><tr><td>HTTP/HTTPS</td><td>获取 HTML、CSS、JS、图片、API 数据</td><td>所有页面加载和 Ajax 请求</td></tr><tr><td>WebSocket</td><td>双向实时通信</td><td>聊天、股票行情、在线协作</td></tr><tr><td>DNS</td><td>将域名（如 <code>api.example.com</code>）转为 IP 地址</td><td>影响首屏加载速度，可通过 <code>dns-prefetch</code> 优化</td></tr></tbody></table><h3 id="客户端-服务端" tabindex="-1">客户端 &amp; 服务端 <a class="header-anchor" href="#客户端-服务端" aria-label="Permalink to &quot;客户端 &amp; 服务端&quot;">​</a></h3><table tabindex="0"><thead><tr><th>角色</th><th>定义</th><th>典型代表</th><th>前端相关职责</th></tr></thead><tbody><tr><td>客户端（Client）</td><td>发起请求的一方，等待并处理响应</td><td>浏览器（Chrome/Firefox）、手机 App、Node.js 脚本</td><td>- 发起 API 请求（<code>fetch</code>/<code>axios</code>）<br>- 渲染页面<br>- 处理用户交互<br>- 管理 Cookie / Token</td></tr><tr><td>服务器（Server）</td><td>接收请求并返回数据的一方</td><td>Web 服务器（Nginx）、后端服务（Node.js/Java/Python）、数据库</td><td>- 提供 HTML/CSS/JS 文件<br>- 处理业务逻辑<br>- 验证身份<br>- 返回 JSON 或静态资源</td></tr></tbody></table><h3 id="ip地址-域名-dns" tabindex="-1">ip地址/域名/DNS <a class="header-anchor" href="#ip地址-域名-dns" aria-label="Permalink to &quot;ip地址/域名/DNS&quot;">​</a></h3><h4 id="_1-ip-地址-internet-protocol-address" tabindex="-1">1. <strong>IP 地址（Internet Protocol Address）</strong> <a class="header-anchor" href="#_1-ip-地址-internet-protocol-address" aria-label="Permalink to &quot;1. **IP 地址（Internet Protocol Address）**&quot;">​</a></h4><ul><li><strong>是什么</strong>：一串数字标识，用于<strong>唯一标识网络中的设备</strong><ul><li>IPv4 示例：<code>114.114.114.114</code></li><li>IPv6 示例：<code>2001:db8::1</code></li></ul></li><li><strong>作用</strong>：网络设备之间通信的“真实地址”，就像电话号码。</li><li><strong>前端视角</strong>： <ul><li>浏览器最终是通过 IP 地址连接服务器的</li></ul></li></ul><blockquote><p>⚠️ 问题：IP 难记、会变（服务器迁移），怎么办？</p></blockquote><h4 id="_2-域名-domain-name" tabindex="-1">2. <strong>域名（Domain Name）</strong> <a class="header-anchor" href="#_2-域名-domain-name" aria-label="Permalink to &quot;2. **域名（Domain Name）**&quot;">​</a></h4><ul><li><strong>是什么</strong>：人类可读的地址，如 <code>www.taobao.com</code>、<code>api.github.com</code></li><li><strong>作用</strong>：代替难记的 IP 地址，方便用户访问和开发者配置</li><li><strong>前端使用场景</strong>：<div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fetch</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://api.example.com/users&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://cdn.jsdelivr.net/npm/vue@3&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div></li></ul><blockquote><p>✅ 域名 = 用户友好的“别名”</p></blockquote><h4 id="_3-dns-domain-name-system-域名系统" tabindex="-1">3. <strong>DNS（Domain Name System，域名系统）</strong> <a class="header-anchor" href="#_3-dns-domain-name-system-域名系统" aria-label="Permalink to &quot;3. **DNS（Domain Name System，域名系统）**&quot;">​</a></h4><ul><li><p><strong>是什么</strong>：一个分布式“电话簿”，<strong>将域名翻译成 IP 地址</strong></p></li><li><p><strong>作用</strong>：当你输入 <code>https://baidu.com</code>，浏览器先问 DNS：“这个域名对应的 IP 是多少？”</p></li><li><p><strong>过程简述</strong>：</p><ol><li>浏览器检查本地缓存 → 操作系统缓存 → 路由器缓存</li><li>若都没命中，向 <strong>DNS 服务器</strong>（如 8.8.8.8）发起查询</li><li>最终拿到 IP（如 <code>220.181.38.148</code>），再建立 TCP 连接</li></ol></li><li><p>🌐 <strong>DNS 查询示意图（简化）</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>前端代码 → 域名 (api.example.com)</span></span>
<span class="line"><span>      ↓</span></span>
<span class="line"><span>  [DNS 查询]</span></span>
<span class="line"><span>      ↓</span></span>
<span class="line"><span>IP 地址 (93.184.216.34)</span></span>
<span class="line"><span>      ↓</span></span>
<span class="line"><span>建立 TCP/TLS 连接 → 发送 HTTP 请求</span></span></code></pre></div></li></ul><h2 id="tcp-udp协议" tabindex="-1">TCP/UDP协议 <a class="header-anchor" href="#tcp-udp协议" aria-label="Permalink to &quot;TCP/UDP协议&quot;">​</a></h2><blockquote><p><strong>位置</strong>：传输层（Transport Layer）<br><strong>作用</strong>：为应用层提供端到端（进程到进程）的数据传输服务</p></blockquote><table tabindex="0"><thead><tr><th>特性</th><th>TCP</th><th>UDP</th></tr></thead><tbody><tr><td><strong>连接方式</strong></td><td>面向连接</td><td>无连接</td></tr><tr><td><strong>可靠性</strong></td><td>可靠传输（保证送达、不丢包、不重复、按序）</td><td>不可靠（尽最大努力交付，不保证）</td></tr><tr><td><strong>数据单位</strong></td><td>字节流（Byte Stream）</td><td>数据报（Datagram）</td></tr><tr><td><strong>传输开销</strong></td><td>高（头部20~60字节，含控制字段）</td><td>低（头部固定8字节）</td></tr><tr><td><strong>传输速度</strong></td><td>较慢（因确认、重传、流量控制等机制）</td><td>快（无连接建立、无确认）</td></tr><tr><td><strong>拥塞控制</strong></td><td>有（慢启动、拥塞避免等）</td><td>无</td></tr><tr><td><strong>适用场景</strong></td><td>文件传输、网页浏览、邮件、数据库访问等</td><td>视频会议、直播、在线游戏、DNS、VoIP</td></tr></tbody></table><h3 id="tcp协议" tabindex="-1">TCP协议 <a class="header-anchor" href="#tcp协议" aria-label="Permalink to &quot;TCP协议&quot;">​</a></h3><h4 id="_1-三次握手-——-建立连接" tabindex="-1">1. <strong>三次握手</strong> —— 建立连接 <a class="header-anchor" href="#_1-三次握手-——-建立连接" aria-label="Permalink to &quot;1. **三次握手** —— 建立连接&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client → Server: SYN (seq=x) 第一次握手：证明客户端能发送</span></span>
<span class="line"><span>Server → Client: SYN-ACK (seq=y, ack=x+1) 第二次握手：证明服务器能接收和发送</span></span>
<span class="line"><span>Client → Server: ACK (ack=y+1) 第三次握手：证明客户端能接收</span></span></code></pre></div><ul><li>目的：同步初始序列号，确保双方收发能力正常</li><li>防止历史重复连接初始化（旧 SYN 报文突然到达）</li></ul><h4 id="_2-四次挥手-——-关闭连接" tabindex="-1">2. <strong>四次挥手</strong> —— 关闭连接 <a class="header-anchor" href="#_2-四次挥手-——-关闭连接" aria-label="Permalink to &quot;2. **四次挥手** —— 关闭连接&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>主动方 → 被动方: FIN</span></span>
<span class="line"><span>被动方 → 主动方: ACK</span></span>
<span class="line"><span>（被动方可能还有数据要发）</span></span>
<span class="line"><span>被动方 → 主动方: FIN</span></span>
<span class="line"><span>主动方 → 被动方: ACK</span></span></code></pre></div><ul><li>TCP 连接是<strong>全双工</strong>的，需双向关闭</li><li>主动关闭方进入 <code>TIME_WAIT</code> 状态（等待 2MSL），确保最后 ACK 被收到</li></ul><h4 id="_3-可靠传输机制" tabindex="-1">3. <strong>可靠传输机制</strong> <a class="header-anchor" href="#_3-可靠传输机制" aria-label="Permalink to &quot;3. **可靠传输机制**&quot;">​</a></h4><ul><li><strong>序列号（Sequence Number）</strong> + <strong>确认号（Acknowledgment Number）</strong>：标识字节流位置，实现按序交付</li><li><strong>超时重传（Retransmission）</strong>：未收到 ACK 则重发</li><li><strong>累计确认（Cumulative ACK）</strong>：确认号表示“该序号前所有数据已收到”</li><li><strong>快速重传（Fast Retransmit）</strong>：收到3个重复 ACK 即重传，不等超时</li></ul><h4 id="_4-流量控制-flow-control" tabindex="-1">4. <strong>流量控制（Flow Control）</strong> <a class="header-anchor" href="#_4-流量控制-flow-control" aria-label="Permalink to &quot;4. **流量控制（Flow Control）**&quot;">​</a></h4><ul><li>使用 <strong>滑动窗口（Sliding Window）</strong> 机制</li><li>接收方通过 <strong>窗口字段（Window Size）</strong> 告知发送方还能接收多少字节</li><li>防止发送方“淹没”接收方缓冲区</li></ul><h4 id="_5-拥塞控制-congestion-control" tabindex="-1">5. <strong>拥塞控制（Congestion Control）</strong> <a class="header-anchor" href="#_5-拥塞控制-congestion-control" aria-label="Permalink to &quot;5. **拥塞控制（Congestion Control）**&quot;">​</a></h4><ul><li>慢启动（Slow Start）：指数增长 cwnd（拥塞窗口）</li><li>拥塞避免（Congestion Avoidance）：线性增长</li><li>快速重传 &amp; 快速恢复（Fast Recovery）</li><li>目标：避免网络过载，公平共享带宽</li></ul><h3 id="udp协议" tabindex="-1">UDP协议 <a class="header-anchor" href="#udp协议" aria-label="Permalink to &quot;UDP协议&quot;">​</a></h3><h4 id="_1-协议结构-头部仅8字节" tabindex="-1">1. <strong>协议结构（头部仅8字节）</strong> <a class="header-anchor" href="#_1-协议结构-头部仅8字节" aria-label="Permalink to &quot;1. **协议结构（头部仅8字节）**&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>| 源端口（2B） | 目的端口（2B） |</span></span>
<span class="line"><span>| 长度（2B）   | 校验和（2B）   |</span></span></code></pre></div><ul><li><strong>长度</strong>：包括头部和数据</li><li><strong>校验和</strong>：可选（IPv4 中可关闭，IPv6 中强制开启），用于检测传输错误</li></ul><h4 id="_2-工作方式" tabindex="-1">2. <strong>工作方式</strong> <a class="header-anchor" href="#_2-工作方式" aria-label="Permalink to &quot;2. **工作方式**&quot;">​</a></h4><ul><li>应用层将数据交给 UDP，UDP 封装成数据报直接交给网络层（IP）</li><li>无连接建立、无状态维护、无重传机制</li><li>每个数据报独立路由，可能乱序、丢失、重复</li></ul><h4 id="_3-优势" tabindex="-1">3. <strong>优势</strong> <a class="header-anchor" href="#_3-优势" aria-label="Permalink to &quot;3. **优势**&quot;">​</a></h4><ul><li>开销小、延迟低</li><li>支持广播/多播（TCP 仅支持单播）</li><li>适用于容忍少量丢包但要求实时性的场景</li></ul><h2 id="http-https协议" tabindex="-1">HTTP/HTTPS协议 <a class="header-anchor" href="#http-https协议" aria-label="Permalink to &quot;HTTP/HTTPS协议&quot;">​</a></h2><h3 id="http-https是什么" tabindex="-1">HTTP/HTTPS是什么 <a class="header-anchor" href="#http-https是什么" aria-label="Permalink to &quot;HTTP/HTTPS是什么&quot;">​</a></h3><p><strong>HTTP（HyperText Transfer Protocol）</strong> 是一种<strong>应用层协议</strong>，用于在客户端（如浏览器）和服务器之间传输超文本（HTML、图片、JSON 等）。它是 Web 的基础。</p><p><strong>特点：</strong></p><ul><li><strong>无状态</strong>：每个请求独立，服务器不保存上下文（需靠 Cookie/Token 维持会话）</li><li><strong>基于请求-响应模型</strong>：客户端发请求 → 服务器返回响应</li><li><strong>明文传输</strong>：数据未加密，容易被窃听或篡改（这是 HTTP 最大缺陷）</li></ul><hr><p><strong>HTTPS（HTTP Secure）</strong> = <strong>HTTP + TLS/SSL 加密层</strong></p><p>它在 HTTP 和 TCP 之间加入了一层<strong>安全传输层（TLS/SSL）</strong>，实现：</p><ul><li><strong>加密</strong>：防止内容被窃听</li><li><strong>完整性校验</strong>：防止数据被篡改</li><li><strong>身份认证</strong>：通过数字证书验证服务器身份</li></ul><blockquote><p>✅ 现代网站几乎都强制使用 HTTPS（浏览器对 HTTP 网站标记为“不安全”）</p></blockquote><hr><table tabindex="0"><thead><tr><th>对比项</th><th>HTTP</th><th>HTTPS</th></tr></thead><tbody><tr><td>默认端口</td><td>80</td><td>443</td></tr><tr><td>安全性</td><td>明文传输，不安全</td><td>加密传输，安全</td></tr><tr><td>性能</td><td>略快（无加密开销）</td><td>略慢（需 TLS 握手），但 HTTP/2 可弥补</td></tr><tr><td>SEO</td><td>搜索引擎降权</td><td>搜索引擎优先收录</td></tr><tr><td>浏览器支持</td><td>所有</td><td>需有效 SSL 证书</td></tr><tr><td>前端限制</td><td>无</td><td>某些 API（如 Geolocation、Service Worker）<strong>仅限 HTTPS</strong></td></tr></tbody></table><h3 id="请求方式" tabindex="-1">请求方式 <a class="header-anchor" href="#请求方式" aria-label="Permalink to &quot;请求方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方法</th><th>全称</th><th>用途</th><th>是否幂等</th><th>是否可缓存</th><th>前端典型使用场景</th></tr></thead><tbody><tr><td><strong>GET</strong></td><td>GET</td><td>获取资源</td><td>✅ 是</td><td>✅ 是</td><td>加载页面、获取列表数据、搜索</td></tr><tr><td><strong>POST</strong></td><td>POST</td><td>提交数据（创建资源）</td><td>❌ 否</td><td>❌ 否</td><td>用户注册、登录、提交表单、上传文件</td></tr><tr><td><strong>PUT</strong></td><td>PUT</td><td><strong>全量更新</strong>资源</td><td>✅ 是</td><td>❌ 否</td><td>修改用户资料（需传完整字段）</td></tr><tr><td><strong>PATCH</strong></td><td>PATCH</td><td><strong>部分更新</strong>资源</td><td>❌ 否（通常视为非幂等）</td><td>❌ 否</td><td>修改用户名、更新头像等局部字段</td></tr><tr><td><strong>DELETE</strong></td><td>DELETE</td><td>删除资源</td><td>✅ 是</td><td>❌ 否</td><td>删除文章、取消关注</td></tr></tbody></table><blockquote><p>🔔 <strong>幂等性（Idempotent）</strong>：多次执行相同请求，结果与执行一次相同（对系统状态影响一致）。<br> ⚠️ <strong>可缓存</strong>：仅 GET 请求默认可被浏览器或代理缓存。</p></blockquote><h3 id="状态码" tabindex="-1">状态码 <a class="header-anchor" href="#状态码" aria-label="Permalink to &quot;状态码&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类别</th><th>含义</th></tr></thead><tbody><tr><td><strong>1xx</strong></td><td>信息性响应（请求已被接收，继续处理）</td></tr><tr><td><strong>2xx</strong></td><td><strong>成功</strong>（请求已成功处理）</td></tr><tr><td><strong>3xx</strong></td><td><strong>重定向</strong>（需进一步操作才能完成请求）</td></tr><tr><td><strong>4xx</strong></td><td><strong>客户端错误</strong>（请求有误或无法完成）</td></tr><tr><td><strong>5xx</strong></td><td><strong>服务器错误</strong>（服务器处理出错）</td></tr></tbody></table><table tabindex="0"><thead><tr><th>状态码</th><th>名称</th><th>含义</th><th>前端场景</th></tr></thead><tbody><tr><td><strong>200</strong></td><td>OK</td><td>请求成功，响应体包含结果</td><td>API 返回数据、页面正常加载</td></tr><tr><td><strong>201</strong></td><td>Created</td><td>资源创建成功</td><td>用户注册、新建文章后返回新资源</td></tr><tr><td><strong>204</strong></td><td>No Content</td><td>请求成功，但无返回内容</td><td>删除操作、更新成功但无需返回数据</td></tr><tr><td><strong>301</strong></td><td>Moved Permanently</td><td>永久重定向（旧 URL 已废弃）</td><td>浏览器/搜索引擎会缓存，自动跳新地址</td></tr><tr><td><strong>302</strong></td><td>Found</td><td>临时重定向</td><td>常用于登录后跳转、A/B 测试</td></tr><tr><td><strong>304</strong></td><td>Not Modified</td><td><strong>协商缓存命中</strong>，资源未修改</td><td>浏览器使用本地缓存，<strong>无响应体</strong></td></tr><tr><td><strong>400</strong></td><td>Bad Request</td><td>请求格式错误（如 JSON 格式不对、参数缺失）</td><td>检查请求体、参数校验</td></tr><tr><td><strong>401</strong></td><td>Unauthorized</td><td><strong>未认证</strong>（缺少或无效 Token/Cookie）</td><td>跳转登录页，清除本地 Token</td></tr><tr><td><strong>403</strong></td><td>Forbidden</td><td><strong>已认证但无权限</strong>访问该资源</td><td>提示“权限不足”，勿跳登录</td></tr><tr><td><strong>404</strong></td><td>Not Found</td><td>请求的资源不存在（路径错误或已被删除）</td><td>检查 API 路径、显示友好 404 页面</td></tr><tr><td><strong>405</strong></td><td>Method Not Allowed</td><td>请求方法不被允许（如对只读接口发 POST）</td><td>检查 API 文档</td></tr><tr><td><strong>429</strong></td><td>Too Many Requests</td><td>请求过于频繁（触发限流）</td><td>提示“操作太频繁，请稍后再试”</td></tr><tr><td><strong>500</strong></td><td>Internal Server Error</td><td>服务器内部错误（代码崩溃、异常未捕获）</td><td>显示“服务异常，请稍后重试”</td></tr><tr><td><strong>502</strong></td><td>Bad Gateway</td><td>网关错误（如 Nginx 无法连接后端服务）</td><td>通常是后端服务宕机</td></tr><tr><td><strong>503</strong></td><td>Service Unavailable</td><td>服务不可用（维护中或过载）</td><td>可提示“系统维护中”</td></tr><tr><td><strong>504</strong></td><td>Gateway Timeout</td><td>网关超时（后端处理太慢）</td><td>建议用户稍后重试</td></tr></tbody></table><h3 id="请求头与响应头" tabindex="-1">请求头与响应头 <a class="header-anchor" href="#请求头与响应头" aria-label="Permalink to &quot;请求头与响应头&quot;">​</a></h3><table tabindex="0"><thead><tr><th>常用请求头</th><th>说明</th><th>前端使用场景</th></tr></thead><tbody><tr><td><code>Accept</code></td><td>告诉服务器客户端能接收的 MIME 类型</td><td><code>Accept: application/json</code> 表示期望返回 JSON</td></tr><tr><td><code>Content-Type</code></td><td>声明请求体的数据格式</td><td>- <code>application/json</code>（JSON API）<br>- <code>multipart/form-data</code>（文件上传）<br>- <code>application/x-www-form-urlencoded</code>（表单提交）</td></tr><tr><td><code>Authorization</code></td><td>携带认证凭证</td><td><code>Authorization: Bearer &lt;token&gt;</code>（JWT 认证）<br><code>Authorization: Basic base64(user:pass)</code></td></tr><tr><td><code>Cookie</code></td><td>自动携带当前域名下的 Cookie</td><td>用于会话保持（如 sessionId），通常由浏览器自动管理</td></tr><tr><td><code>User-Agent</code></td><td>标识客户端（浏览器/设备信息）</td><td>后端可据此做兼容处理（前端一般不修改）</td></tr><tr><td><code>Referer</code></td><td>当前页面 URL（来源页）</td><td>用于防盗链、统计分析（注意：可能被隐私策略屏蔽）</td></tr><tr><td><code>Origin</code></td><td>跨域请求时标识请求来源（协议+域名+端口）</td><td>CORS 判断是否允许跨域的关键字段</td></tr><tr><td><code>If-None-Match</code></td><td>携带 ETag 值，用于协商缓存</td><td>浏览器自动设置，若资源未变，服务器返回 304</td></tr><tr><td><code>If-Modified-Since</code></td><td>携带上次修改时间，用于协商缓存</td><td>同上，基于时间戳的缓存验证</td></tr></tbody></table><table tabindex="0"><thead><tr><th>常用响应头</th><th>说明</th><th>前端影响</th></tr></thead><tbody><tr><td><code>Content-Type</code></td><td>响应体的 MIME 类型和编码</td><td>决定浏览器如何解析内容：<br>- <code>text/html; charset=utf-8</code> → 渲染 HTML<br>- <code>application/json</code> → 可被 <code>res.json()</code> 解析</td></tr><tr><td><code>Set-Cookie</code></td><td>服务器设置 Cookie</td><td>浏览器自动存储，并在后续请求中通过 <code>Cookie</code> 头发送<br>可带属性：<code>HttpOnly</code>、<code>Secure</code>、<code>SameSite</code>、<code>Path</code></td></tr><tr><td><code>Cache-Control</code></td><td>控制缓存策略（最重要！）</td><td>- <code>max-age=3600</code>：强缓存 1 小时<br>- <code>no-cache</code>：走协商缓存<br>- <code>no-store</code>：禁止缓存（敏感数据）</td></tr><tr><td><code>ETag</code></td><td>资源唯一标识（类似指纹）</td><td>用于协商缓存，下次请求通过 <code>If-None-Match</code> 对比</td></tr><tr><td><code>Last-Modified</code></td><td>资源最后修改时间</td><td>协商缓存备用方案（精度低，不如 ETag）</td></tr><tr><td><code>Access-Control-Allow-Origin</code></td><td>CORS 允许的源</td><td>如 <code>Access-Control-Allow-Origin: https://example.com</code><br>或 <code>*</code>（仅限不带凭证的请求）</td></tr><tr><td><code>Access-Control-Allow-Credentials</code></td><td>是否允许携带 Cookie</td><td>设为 <code>true</code> 时，前端需设置 <code>credentials: &#39;include&#39;</code></td></tr><tr><td><code>Location</code></td><td>重定向目标 URL</td><td>配合 3xx 状态码使用（如 302）</td></tr><tr><td><code>Content-Encoding</code></td><td>响应体压缩方式</td><td>如 <code>gzip</code>、<code>br</code>（Brotli），浏览器自动解压</td></tr><tr><td><code>Content-Security-Policy</code> (CSP)</td><td>定义资源加载白名单</td><td>防 XSS 攻击，限制 script/style/img 等来源</td></tr></tbody></table><h3 id="http版本" tabindex="-1">HTTP版本 <a class="header-anchor" href="#http版本" aria-label="Permalink to &quot;HTTP版本&quot;">​</a></h3><h4 id="一、http-1-0-1996-年" tabindex="-1">一、HTTP/1.0（1996 年） <a class="header-anchor" href="#一、http-1-0-1996-年" aria-label="Permalink to &quot;一、HTTP/1.0（1996 年）&quot;">​</a></h4><p>核心特点：</p><ul><li><strong>每个请求都要新建 TCP 连接</strong>，用完即关。</li><li>无持久连接（Keep-Alive 需手动开启）。</li><li>无 Host 头（无法在同一 IP 上部署多个网站）。</li></ul><p>前端影响： ❌ 性能极差：加载一个页面（含 CSS/JS/图片）需建立多次 TCP 连接（三次握手开销大）。<br> ✅ 现代浏览器和服务器<strong>已不再使用纯 HTTP/1.0</strong>。</p><hr><h4 id="二、http-1-1-1999-年-至今仍广泛兼容" tabindex="-1">二、HTTP/1.1（1999 年，至今仍广泛兼容） <a class="header-anchor" href="#二、http-1-1-1999-年-至今仍广泛兼容" aria-label="Permalink to &quot;二、HTTP/1.1（1999 年，至今仍广泛兼容）&quot;">​</a></h4><p>核心改进：</p><ul><li>✅ <strong>持久连接（Persistent Connection）</strong>：默认复用 TCP 连接（<code>Connection: keep-alive</code>）。</li><li>✅ <strong>Host 头</strong>：支持虚拟主机（同一 IP 托管多个域名）。</li><li>✅ <strong>缓存控制</strong>：引入 <code>Cache-Control</code>、<code>ETag</code> 等更精细的缓存机制。</li><li>✅ <strong>分块传输（Chunked Transfer）</strong>：支持流式响应。</li></ul><p>仍存在的问题（对前端性能不利）：</p><ul><li>❌ <strong>队头阻塞（Head-of-Line Blocking）</strong>：<br> 同一 TCP 连接上，请求必须<strong>按顺序处理</strong>。若第一个请求慢，后面的都得等。</li><li>❌ <strong>头部冗余</strong>：每个请求都携带重复的 Cookie、User-Agent 等，浪费带宽。</li></ul><p>前端应对策略（HTTP/1.1 时代）：</p><ul><li>合并 JS/CSS 文件（减少请求数）</li><li>使用雪碧图（CSS Sprite）</li><li>域名分片（Domain Sharding）：用多个子域名并行加载资源（如 <code>static1.example.com</code>）</li></ul><blockquote><p>⚠️ 注意：这些“优化”在 HTTP/2 下反而<strong>有害</strong>！</p></blockquote><hr><h4 id="三、http-2-2015-年标准化-现代主流" tabindex="-1">三、HTTP/2（2015 年标准化，现代主流） <a class="header-anchor" href="#三、http-2-2015-年标准化-现代主流" aria-label="Permalink to &quot;三、HTTP/2（2015 年标准化，现代主流）&quot;">​</a></h4><p>核心特性（解决 HTTP/1.1 痛点）：</p><ul><li>✅ <strong>多路复用（Multiplexing）</strong>：<br> 同一 TCP 连接上可<strong>并行发送多个请求/响应</strong>，彻底解决队头阻塞。</li><li>✅ <strong>头部压缩（HPACK）</strong>：<br> 使用静态/动态字典压缩 Header，减少体积（尤其对含大 Cookie 的请求效果显著）。</li><li>✅ <strong>二进制分帧（Binary Framing）</strong>：<br> 将请求/响应拆分为帧（Frame），更高效解析。</li><li>✅ <strong>服务端推送（Server Push）</strong>（较少使用）：<br> 服务器可主动推送资源（如 HTML 返回时预推 CSS/JS）。</li></ul><p>对前端的影响：</p><ul><li>✅ <strong>无需合并文件</strong>：小文件独立加载更利于缓存更新。</li><li>✅ <strong>无需域名分片</strong>：单域名即可高效并行。</li><li>✅ <strong>首屏加载更快</strong>：关键资源可优先传输。</li></ul><hr><h4 id="四、http-3-2022-年正式标准化-逐步普及" tabindex="-1">四、HTTP/3（2022 年正式标准化，逐步普及） <a class="header-anchor" href="#四、http-3-2022-年正式标准化-逐步普及" aria-label="Permalink to &quot;四、HTTP/3（2022 年正式标准化，逐步普及）&quot;">​</a></h4><p>核心变革：</p><ul><li>✅ <strong>底层从 TCP 改为 UDP</strong>（基于 <strong>QUIC 协议</strong>）。</li><li>✅ <strong>解决 TCP 层的队头阻塞</strong>：<br> TCP 中一个包丢失会导致整个连接等待重传；而 QUIC 在<strong>连接内每个流独立</strong>，丢包不影响其他流。</li><li>✅ <strong>更快的连接建立</strong>：<br> TLS 1.3 + QUIC 握手可在 <strong>1 个 RTT 甚至 0 RTT</strong> 完成（比 HTTP/2 更快）。</li><li>✅ <strong>连接迁移</strong>：<br> 切换网络（如 WiFi → 4G）时，连接不中断（适合移动端）。</li></ul><p>对前端的意义：</p><ul><li>🚀 <strong>弱网环境下体验显著提升</strong>（视频、游戏、实时应用受益大）。</li><li>🌐 <strong>更适合移动 Web 应用</strong>。</li><li>🔒 依然强制 HTTPS。</li></ul><hr><h4 id="五、http版本对比" tabindex="-1">五、HTTP版本对比 <a class="header-anchor" href="#五、http版本对比" aria-label="Permalink to &quot;五、HTTP版本对比&quot;">​</a></h4><table tabindex="0"><thead><tr><th>特性</th><th>HTTP/1.1</th><th>HTTP/2</th><th>HTTP/3</th></tr></thead><tbody><tr><td>传输层</td><td>TCP</td><td>TCP</td><td><strong>UDP (QUIC)</strong></td></tr><tr><td>多路复用</td><td>❌</td><td>✅</td><td>✅（更优）</td></tr><tr><td>队头阻塞</td><td>✅（连接级）</td><td>❌（流级解决）</td><td>❌（完全解决）</td></tr><tr><td>头部压缩</td><td>❌</td><td>✅（HPACK）</td><td>✅（QPACK）</td></tr><tr><td>加密</td><td>可选（HTTP/HTTPS）</td><td><strong>强制 HTTPS</strong></td><td><strong>强制 HTTPS</strong></td></tr><tr><td>连接建立速度</td><td>慢（TCP + TLS）</td><td>较快（TLS 1.2/1.3）</td><td><strong>极快（0-RTT）</strong></td></tr><tr><td>前端优化重点</td><td>合并资源、域名分片</td><td>按需加载、模块化</td><td>无需特殊优化</td></tr></tbody></table><h2 id="同源策略与跨域-cors" tabindex="-1">同源策略与跨域(CORS) <a class="header-anchor" href="#同源策略与跨域-cors" aria-label="Permalink to &quot;同源策略与跨域(CORS)&quot;">​</a></h2><p><strong>同源（Same Origin）</strong> 指两个 URL 的以下三部分<strong>完全相同</strong>：</p><ul><li><strong>协议（Protocol）</strong>：如 <code>http</code> / <code>https</code></li><li><strong>域名（Host）</strong>：如 <code>www.example.com</code></li><li><strong>端口（Port）</strong>：如 <code>80</code>（HTTP 默认）、<code>443</code>（HTTPS 默认）、<code>3000</code></li></ul><h3 id="同源策略" tabindex="-1">同源策略 <a class="header-anchor" href="#同源策略" aria-label="Permalink to &quot;同源策略&quot;">​</a></h3><p>「同源策略」（Same-Origin Policy）是浏览器的一项<strong>安全机制</strong>，用于限制一个源的文档或脚本如何与另一个源的资源进行交互。</p><p><strong>浏览器限制的行为包括：</strong></p><ul><li>❌ 通过 <code>fetch</code>/<code>XMLHttpRequest</code> 读取<strong>非同源</strong>的响应内容（即使请求发出去了）</li><li>❌ 访问非同源 iframe 的 DOM</li><li>❌ 读取非同源 Cookie、LocalStorage（但 Cookie 可通过设置 <code>Domain</code> 共享子域）</li></ul><blockquote><p>✅ 允许的行为（不会被阻止）：</p><ul><li><code>&lt;img&gt;</code>、<code>&lt;script&gt;</code>、<code>&lt;link&gt;</code>、<code>&lt;video&gt;</code> 等标签加载跨域资源（但无法读取其内容）</li><li>表单提交到跨域地址（但 JS 无法读取响应）</li></ul></blockquote><h3 id="跨域" tabindex="-1">跨域 <a class="header-anchor" href="#跨域" aria-label="Permalink to &quot;跨域&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方案</th><th>是否需后端配合</th><th>支持方法</th><th>适用场景</th><th>推荐度</th></tr></thead><tbody><tr><td><strong>CORS</strong></td><td>✅ 是</td><td>所有</td><td>生产环境标准方案</td><td>⭐⭐⭐⭐⭐</td></tr><tr><td><strong>开发代理</strong></td><td>❌ 否</td><td>所有</td><td>本地开发</td><td>⭐⭐⭐⭐⭐</td></tr><tr><td><strong>Nginx 代理</strong></td><td>❌（需运维）</td><td>所有</td><td>生产环境部署</td><td>⭐⭐⭐⭐</td></tr><tr><td><strong>JSONP</strong></td><td>✅ 是</td><td>仅 GET</td><td>老系统兼容</td><td>⭐</td></tr></tbody></table><h4 id="_1-cors-跨域资源共享-——-生产环境首选" tabindex="-1">1. CORS（跨域资源共享）—— <strong>生产环境首选</strong> <a class="header-anchor" href="#_1-cors-跨域资源共享-——-生产环境首选" aria-label="Permalink to &quot;1. CORS（跨域资源共享）—— **生产环境首选**&quot;">​</a></h4><p><strong>原理：</strong> 后端在响应头中添加 <code>Access-Control-Allow-Origin</code> 等字段，<strong>显式授权</strong>前端域名访问。</p><p><strong>适用场景：</strong> 前后端分离项目（如 Vue/React + Spring Boot/Node.js）、第三方 API 支持 CORS。</p><p><strong>优点：</strong> 标准化、安全、支持所有 HTTP 方法（GET/POST/PUT/DELETE）、浏览器原生支持。</p><p><strong>缺点：</strong> 需要<strong>后端配合</strong>，复杂请求会触发预检（OPTIONS），增加一次网络往返。</p><blockquote><p>⚠️ 若使用 <code>credentials: true</code>，<code>Allow-Origin</code> 不能为 <code>*</code>，必须指定具体域名。</p></blockquote><hr><h4 id="_2-开发代理-devserver-proxy-——-开发环境首选" tabindex="-1">2. 开发代理（DevServer Proxy）—— <strong>开发环境首选</strong> <a class="header-anchor" href="#_2-开发代理-devserver-proxy-——-开发环境首选" aria-label="Permalink to &quot;2. 开发代理（DevServer Proxy）—— **开发环境首选**&quot;">​</a></h4><p><strong>原理：</strong> 前端开发服务器（如 Webpack DevServer、Vite）作为<strong>代理</strong>，将 <code>/api</code> 开头的请求转发到后端真实地址。→ 浏览器认为是同源请求，无跨域。</p><p><strong>适用场景：</strong> 本地开发（前端 <code>localhost:3000</code>，后端 <code>localhost:8080</code>）。</p><p><strong>优点：</strong> <strong>无需后端改代码</strong>，配置简单，热更新友好。</p><p><strong>缺点：</strong> <strong>仅限开发环境</strong>，生产环境无效。</p><hr><h4 id="_3-nginx-反向代理-——-生产环境高性能方案" tabindex="-1">3. Nginx 反向代理 —— <strong>生产环境高性能方案</strong> <a class="header-anchor" href="#_3-nginx-反向代理-——-生产环境高性能方案" aria-label="Permalink to &quot;3. Nginx 反向代理 —— **生产环境高性能方案**&quot;">​</a></h4><p><strong>原理：</strong> 通过 Nginx 将前端域名下的 <code>/api</code> 路径<strong>代理</strong>到后端服务。→ 浏览器只与 Nginx 通信（同源），Nginx 再转发给后端。</p><p><strong>适用场景：</strong> 生产环境部署（尤其高并发项目），无法修改后端 CORS 配置时。</p><p><strong>优点：</strong> 统一入口，便于负载均衡、SSL 终止，对前端透明，<strong>前后端均无需特殊处理</strong>。</p><p><strong>缺点：</strong> 需要运维介入配置。</p><hr><h4 id="_4-jsonp-——-仅用于兼容老系统" tabindex="-1">4. JSONP —— <strong>仅用于兼容老系统</strong> <a class="header-anchor" href="#_4-jsonp-——-仅用于兼容老系统" aria-label="Permalink to &quot;4. JSONP —— **仅用于兼容老系统**&quot;">​</a></h4><p><strong>原理：</strong> 利用 <code>&lt;script&gt;</code> 标签<strong>不受同源策略限制</strong>的特性，动态加载 JS 文件，服务器返回“回调函数包裹的数据”。</p><p><strong>适用场景：</strong> 调用<strong>只支持 JSONP 的第三方接口</strong>（如某些老地图 API），需兼容 IE8/9 等老旧浏览器。</p><p><strong>优点：</strong> 兼容性极好</p><p><strong>缺点：</strong> <strong>仅支持 GET 请求</strong>，有 XSS 安全风险，无法处理错误状态码（如 500）</p><blockquote><p>🚫 现代项目<strong>不推荐使用</strong>！</p></blockquote><h2 id="浏览器缓存机制" tabindex="-1">浏览器缓存机制 <a class="header-anchor" href="#浏览器缓存机制" aria-label="Permalink to &quot;浏览器缓存机制&quot;">​</a></h2><p>浏览器缓存机制是前端性能优化的核心手段之一，它能显著减少网络请求、加快页面加载速度。浏览器缓存主要分为两类：<strong>强缓存</strong> 和 <strong>协商缓存</strong>。</p><p><img src="`+a+`" alt="浏览器缓存机制示意图"></p><ul><li>优先级 <ol><li><strong>强缓存优先</strong>：如果 <code>Cache-Control</code> 或 <code>Expires</code> 有效，直接使用缓存，<strong>不发请求</strong>。</li><li><strong>强缓存失效后</strong>，才进入协商缓存阶段。</li><li><strong>ETag 优先级高于 Last-Modified</strong>：如果两者都存在，服务器优先校验 ETag。</li></ol></li></ul><h3 id="强缓存" tabindex="-1">强缓存 <a class="header-anchor" href="#强缓存" aria-label="Permalink to &quot;强缓存&quot;">​</a></h3><blockquote><p><strong>特点</strong>：命中后<strong>不发请求到服务器</strong>，直接使用本地缓存。</p></blockquote><table tabindex="0"><thead><tr><th>响应头字段</th><th>说明</th><th>优先级</th></tr></thead><tbody><tr><td><code>Cache-Control</code></td><td>HTTP/1.1 标准，功能强大</td><td><strong>高</strong>（优先于 Expires）</td></tr><tr><td><code>Expires</code></td><td>HTTP/1.0 字段，指定过期时间（GMT）</td><td>低</td></tr></tbody></table><table tabindex="0"><thead><tr><th>常用<code>Cache-Control</code>指令</th><th>作用</th></tr></thead><tbody><tr><td><code>max-age=3600</code></td><td>缓存 3600 秒（相对时间）</td></tr><tr><td><code>no-cache</code></td><td><strong>跳过强缓存，但走协商缓存</strong>（常被误解为“不缓存”）</td></tr><tr><td><code>no-store</code></td><td><strong>禁止一切缓存</strong>（敏感数据如银行页面）</td></tr><tr><td><code>public</code></td><td>可被任何中间代理缓存</td></tr><tr><td><code>private</code></td><td>仅用户浏览器可缓存（默认）</td></tr></tbody></table><h3 id="协商缓存" tabindex="-1">协商缓存 <a class="header-anchor" href="#协商缓存" aria-label="Permalink to &quot;协商缓存&quot;">​</a></h3><blockquote><p><strong>特点</strong>：<strong>会发请求到服务器</strong>，但服务器根据条件判断是否返回新内容。若未修改，返回 <code>304 Not Modified</code>，浏览器使用本地缓存。</p></blockquote><ul><li><p>方式 1：Last-Modified / If-Modified-Since</p><ul><li><strong>服务器逻辑</strong>：比较文件最后修改时间，若未变 → 返回 <code>304</code></li></ul><blockquote><p>⚠️ 缺陷：</p><ul><li>时间精度只到秒，1 秒内多次修改无法识别；</li><li>文件内容未变但时间戳变了，会误判为已修改。</li></ul></blockquote></li><li><p>方式 2：ETag / If-None-Match（推荐）</p><ul><li><strong>服务器逻辑</strong>：比对 ETag，一致 → 返回 <code>304</code></li></ul></li></ul><h2 id="网络安全" tabindex="-1">网络安全 <a class="header-anchor" href="#网络安全" aria-label="Permalink to &quot;网络安全&quot;">​</a></h2><h3 id="xss攻击" tabindex="-1">XSS攻击 <a class="header-anchor" href="#xss攻击" aria-label="Permalink to &quot;XSS攻击&quot;">​</a></h3><p><strong>XSS（跨站脚本攻击，Cross-Site Scripting）</strong></p><ul><li><p><strong>原理：</strong> 攻击者向网页中注入恶意脚本（通常是 JavaScript），当其他用户浏览该页面时，脚本在受害者浏览器中执行，从而窃取 Cookie、会话令牌、重定向到钓鱼网站等。</p></li><li><p><strong>主要类型：</strong></p><table tabindex="0"><thead><tr><th>类型</th><th>特点</th><th>示例场景</th></tr></thead><tbody><tr><td><strong>存储型 XSS</strong></td><td>恶意脚本永久存储在服务器（如评论、帖子）</td><td>用户发布含 <code>&lt;script&gt;</code> 的评论，所有访问者中招</td></tr><tr><td><strong>反射型 XSS</strong></td><td>恶意脚本通过 URL 参数传入，服务器反射回页面</td><td>诱导用户点击 <code>?search=&lt;script&gt;...&lt;/script&gt;</code> 链接</td></tr><tr><td><strong>DOM 型 XSS</strong></td><td>漏洞在前端 JavaScript 中，不经过服务器</td><td><code>location.hash</code> 被直接写入 DOM</td></tr></tbody></table></li><li><p><strong>危害：</strong></p><ol><li>窃取用户 Cookie / Session ID（尤其是未设 <code>HttpOnly</code> 的）</li><li>劫持用户操作（如发帖、转账）</li><li>植入键盘记录器、挖矿脚本等</li></ol></li><li><p><strong>防御措施：</strong></p><ol><li>输入过滤与转义：对用户输入的 <code>&lt;</code>, <code>&gt;</code>, <code>&amp;</code>, <code>&quot;</code>, <code>&#39;</code> 等字符进行 HTML 实体编码。</li><li>输出编码：根据上下文（HTML、JS、URL）做不同转义。</li><li>设置 Cookie 安全属性： <ul><li><code>HttpOnly</code>：禁止 JS 访问 Cookie</li><li><code>Secure</code>：仅 HTTPS 传输</li></ul></li><li>使用 CSP（见下文）</li><li>避免直接操作 DOM（如慎用 <code>innerHTML</code>, <code>eval()</code>）</li></ol></li></ul><h3 id="csrf攻击" tabindex="-1">CSRF攻击 <a class="header-anchor" href="#csrf攻击" aria-label="Permalink to &quot;CSRF攻击&quot;">​</a></h3><p><strong>CSRF（跨站请求伪造，Cross-Site Request Forgery）</strong></p><ul><li><p><strong>原理：</strong> 攻击者诱导已登录用户在不知情的情况下，向目标网站发起<strong>非自愿的请求</strong>（如修改密码、转账）。由于浏览器自动携带 Cookie，服务器误认为是合法操作。</p><blockquote><p>前提：用户已登录目标网站，且认证依赖 Cookie。</p></blockquote></li><li><p><strong>攻击示例：</strong></p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">&lt;!-- 攻击者网站上的图片 --&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">img</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://bank.com/transfer?to=attacker&amp;amount=1000&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span></code></pre></div><p>用户访问该页面时，浏览器自动携带 <code>bank.com</code> 的 Cookie 发起转账请求。</p></li><li><p><strong>危害：</strong></p><ol><li>非授权资金转移</li><li>修改账户信息（邮箱、密码）</li><li>删除数据等破坏性操作</li></ol></li><li><p><strong>防御措施：</strong></p><ol><li>使用 CSRF Token： <ul><li>服务端生成随机 token，嵌入表单或 header</li><li>每次请求需携带该 token，服务端校验</li></ul></li><li>检查 <code>Origin</code> / <code>Referer</code> 头（辅助手段，不可靠）</li><li>关键操作要求二次验证（如短信验证码、密码确认）</li><li>设置 Cookie 的 <code>SameSite</code> 属性： <ul><li><code>SameSite=Lax</code>：允许同站 GET 请求（兼顾安全与体验）</li><li><code>SameSite=Strict</code>：完全禁止跨站携带 Cookie（更安全但影响部分功能）</li></ul></li></ol><blockquote><p>💡 注意：<strong>CSRF 无法窃取数据，只能“冒用身份发起操作”</strong>；而 XSS 可以读取页面任意内容。</p></blockquote></li></ul><h3 id="csp内容安全策略" tabindex="-1">CSP内容安全策略 <a class="header-anchor" href="#csp内容安全策略" aria-label="Permalink to &quot;CSP内容安全策略&quot;">​</a></h3><p><strong>CSP（内容安全策略，Content Security Policy）</strong></p><ul><li><p><strong>原理：</strong> 通过 HTTP 响应头 <code>Content-Security-Policy</code>，<strong>白名单机制</strong>限制浏览器可加载和执行的资源（脚本、样式、图片、iframe 等），从源头阻断 XSS、数据注入等攻击。</p></li><li><p><strong>核心指令示例：</strong></p><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Content-Security-Policy</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  default-src &#39;self&#39;;                     /* 默认只加载同源资源 */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  script-src &#39;self&#39; https://cdn.example.com &#39;unsafe-inline&#39;; /* 脚本来源 */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  style-src &#39;self&#39; &#39;unsafe-inline&#39;;       /* 样式来源 */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  img-src *;                              /* 图片可来自任意域 */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  connect-src &#39;self&#39;;                     /* AJAX/fetch 仅限同源 */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  frame-ancestors &#39;none&#39;;                 /* 禁止被嵌入 iframe（防点击劫持） */</span></span></code></pre></div></li></ul>`,169)])])}const b=o(s,[["render",n]]);export{u as __pageData,b as default};
